import{_ as e,o as s,c as r,a3 as t}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"48. Special Rates For Saturdays And Sundays","description":"","frontmatter":{"title":"48. Special Rates For Saturdays And Sundays","eba":"Nurses and Midwives 2024-2028","topics":["hours","overtime"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/48-special-rates-for-saturdays-and-sundays.md","filePath":"ebas/nurses-midwives/hours-of-work/48-special-rates-for-saturdays-and-sundays.md"}'),o={name:"ebas/nurses-midwives/hours-of-work/48-special-rates-for-saturdays-and-sundays.md"};function n(d,a,i,u,l,p){return s(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="_48-special-rates-for-saturdays-and-sundays" tabindex="-1">48. Special Rates For Saturdays And Sundays <a class="header-anchor" href="#_48-special-rates-for-saturdays-and-sundays" aria-label="Permalink to &quot;48. Special Rates For Saturdays And Sundays&quot;">​</a></h1><p>This clause does not apply to DONs and Deputy DONs.</p><p>The term ‘ordinary hours of work’ is a reference to hours of work that are not at overtime rates.</p><p><strong>48.1</strong> All ordinary hours of work between midnight on Friday and midnight on Sunday will be paid for at the rate of time and a half.</p><p><strong>48.2</strong> For a casual Employee – all ordinary hours of work between midnight on Friday and midnight on Sunday will be paid for at the rate of 187.5% from 17 May 2024.</p><p><strong>48.3</strong> The rates for overtime performed between midnight on Friday and midnight on Sunday are set out at <a href="/eba/ebas/nurses-midwives/hours-of-work/49-overtime.html">clause 49</a> (Overtime).</p><p>Plain language terms: weekend penalty, weekend loading, weekend rates.</p>',7)])])}const m=e(o,[["render",n]]);export{f as __pageData,m as default};
